-- ============================================================================
-- Fideon OS — COMBINED migrations (single-file apply)
-- Generated by concatenating supabase/migrations/*.sql in lexicographic order.
-- Run ONCE against a FRESH database (e.g. paste into the Supabase SQL editor).
-- Wrapped in a single transaction: if any statement fails, NOTHING is applied.
-- Do NOT edit here — edit the source files in migrations/ and regenerate.
-- ============================================================================

BEGIN;

-- ============================================================================
-- >>> 20260522010000_create_users.sql
-- ============================================================================
-- public.users — central identity table (replaces auth.users for all app logic)
-- FastAPI owns the entire auth layer; Supabase is DB-only.
-- See: backend/docs/Auth_Module_Plan.md §2.1

CREATE TABLE public.users (
  id                UUID        PRIMARY KEY DEFAULT gen_random_uuid(),
  email             TEXT        NOT NULL UNIQUE,
  password_hash     TEXT        NOT NULL,
  status            TEXT        NOT NULL DEFAULT 'pending'
                    CHECK (status IN ('active','pending','locked','suspended')),
  email_verified_at TIMESTAMPTZ,
  failed_attempts   INT         NOT NULL DEFAULT 0,
  locked_until      TIMESTAMPTZ,
  full_name         TEXT,
  last_sign_in_at   TIMESTAMPTZ,
  created_at        TIMESTAMPTZ NOT NULL DEFAULT now(),
  updated_at        TIMESTAMPTZ NOT NULL DEFAULT now()
);

CREATE OR REPLACE FUNCTION public.set_updated_at()
RETURNS TRIGGER LANGUAGE plpgsql AS $$
BEGIN NEW.updated_at = now(); RETURN NEW; END;
$$;

CREATE TRIGGER users_updated_at
  BEFORE UPDATE ON public.users
  FOR EACH ROW EXECUTE FUNCTION public.set_updated_at();

CREATE INDEX users_email_idx  ON public.users (email);
CREATE INDEX users_status_idx ON public.users (status);

ALTER TABLE public.users ENABLE ROW LEVEL SECURITY;


-- ============================================================================
-- >>> 20260522010100_create_otp_codes.sql
-- ============================================================================
-- public.otp_codes — transient OTP state, separate from users
-- One row per user (UNIQUE). Deleted on successful verify, expiry, or max attempts.
-- See: backend/docs/Auth_Module_Plan.md §2.2

CREATE TABLE public.otp_codes (
  id            UUID        PRIMARY KEY DEFAULT gen_random_uuid(),
  user_id       UUID        NOT NULL UNIQUE REFERENCES public.users(id) ON DELETE CASCADE,
  otp_code_hash TEXT        NOT NULL,
  expires_at    TIMESTAMPTZ NOT NULL,
  attempt_count INT         NOT NULL DEFAULT 0,
  resend_count  INT         NOT NULL DEFAULT 0,
  created_at    TIMESTAMPTZ NOT NULL DEFAULT now()
);

CREATE INDEX otp_codes_user_id_idx ON public.otp_codes (user_id);

ALTER TABLE public.otp_codes ENABLE ROW LEVEL SECURITY;


-- ============================================================================
-- >>> 20260522010200_create_invites.sql
-- ============================================================================
-- public.invites — invite-only signup gate
-- Raw token only in the email link; DB stores SHA-256 hash only.
-- See: backend/docs/Auth_Module_Plan.md §2.3

CREATE TABLE public.invites (
