-- ============================================================================
-- >>> 20260523000100_fn_signup_atomic.sql
-- ============================================================================
-- Atomic signup: accepts invite + creates user + assigns role in one transaction.
-- Called via supabase.rpc('signup_atomic', {...})
CREATE OR REPLACE FUNCTION public.signup_atomic(
    p_token_hash  TEXT,
    p_password_hash TEXT,
    p_now         TIMESTAMPTZ DEFAULT now()
)
RETURNS JSON
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public, pg_temp
AS $$
DECLARE
    v_invite      RECORD;
    v_user_id     UUID;
    v_result      JSON;
BEGIN
    -- Lock and validate invite row
    SELECT id, email, status, expires_at
    INTO v_invite
    FROM public.invites
    WHERE token_hash = p_token_hash
      AND status = 'PENDING'
      AND expires_at > p_now
    FOR UPDATE;

    IF NOT FOUND THEN
        RETURN json_build_object('error', 'invalid_invite');
    END IF;

    -- Mark invite accepted
    UPDATE public.invites
    SET status = 'ACCEPTED'
    WHERE id = v_invite.id;

    -- Create user
    INSERT INTO public.users (email, password_hash, status)
    VALUES (v_invite.email, p_password_hash, 'pending')
    RETURNING id INTO v_user_id;

    -- Assign default role
    INSERT INTO public.user_roles (user_id, role)
    VALUES (v_user_id, 'user');

    RETURN json_build_object('user_id', v_user_id, 'email', v_invite.email);
END;
$$;

-- Only the service role (FastAPI backend) may call this function
REVOKE EXECUTE ON FUNCTION public.signup_atomic FROM PUBLIC, anon, authenticated;
GRANT EXECUTE ON FUNCTION public.signup_atomic TO service_role;


-- ============================================================================
-- >>> 20260523000200_fix_rls_custom_auth.sql
-- ============================================================================
-- RLS policies on these tables used auth.uid() which only works with Supabase Auth.
-- Since we use zero Supabase Auth (custom FastAPI RS256), auth.uid() always returns NULL
-- and every policy would silently block all access.
--
-- Fix: drop the auth.uid()-based policies and replace with service_role-only access.
-- FastAPI connects as service_role via the service role key — identity is enforced at
-- the API layer by JWT validation, not at the DB layer for these tables.

-- ── user_agents ───────────────────────────────────────────────────────────────
DROP POLICY IF EXISTS user_agents_user ON public.user_agents;
CREATE POLICY user_agents_service ON public.user_agents
  FOR ALL TO service_role USING (true) WITH CHECK (true);

-- ── user_agent_stats ──────────────────────────────────────────────────────────
DROP POLICY IF EXISTS uas_user ON public.user_agent_stats;
CREATE POLICY uas_service ON public.user_agent_stats
  FOR ALL TO service_role USING (true) WITH CHECK (true);

-- ── agent_runs ────────────────────────────────────────────────────────────────
DROP POLICY IF EXISTS agent_runs_user ON public.agent_runs;
CREATE POLICY agent_runs_service ON public.agent_runs
  FOR ALL TO service_role USING (true) WITH CHECK (true);

-- ── agent_run_approvals ───────────────────────────────────────────────────────
DROP POLICY IF EXISTS ara_user ON public.agent_run_approvals;
CREATE POLICY ara_service ON public.agent_run_approvals
  FOR ALL TO service_role USING (true) WITH CHECK (true);

-- ── agent_access_requests ─────────────────────────────────────────────────────
DROP POLICY IF EXISTS aar_user ON public.agent_access_requests;
CREATE POLICY aar_service ON public.agent_access_requests
  FOR ALL TO service_role USING (true) WITH CHECK (true);

-- ── custom_agent_requests ─────────────────────────────────────────────────────
DROP POLICY IF EXISTS car_user ON public.custom_agent_requests;
CREATE POLICY car_service ON public.custom_agent_requests
  FOR ALL TO service_role USING (true) WITH CHECK (true);


-- ============================================================================
-- >>> 20260523000300_fix_custom_agents_fk.sql
-- ============================================================================
-- custom_agent_requests.custom_agent_id references public.custom_agents(id)
-- but the custom_agents table was not created before custom_agent_requests.
-- Fix: create custom_agents now, then restore the FK on custom_agent_requests.

CREATE TABLE IF NOT EXISTS public.custom_agents (
  id           UUID        PRIMARY KEY DEFAULT gen_random_uuid(),
  title        TEXT        NOT NULL,
  description  TEXT,
  status       TEXT        NOT NULL DEFAULT 'building'
               CHECK (status IN ('building','testing','live','deprecated')),
  created_by   UUID        REFERENCES public.users(id),
  created_at   TIMESTAMPTZ NOT NULL DEFAULT now(),
  updated_at   TIMESTAMPTZ NOT NULL DEFAULT now()
);

CREATE TRIGGER custom_agents_updated_at
  BEFORE UPDATE ON public.custom_agents
  FOR EACH ROW EXECUTE FUNCTION public.set_updated_at();

ALTER TABLE public.custom_agents ENABLE ROW LEVEL SECURITY;

CREATE POLICY custom_agents_service ON public.custom_agents
  FOR ALL TO service_role USING (true) WITH CHECK (true);

-- custom_agent_id column already exists from migration 020800 (no FK yet).
-- Now that custom_agents exists, add the FK constraint.
ALTER TABLE public.custom_agent_requests
  ADD CONSTRAINT custom_agent_requests_custom_agent_id_fkey
  FOREIGN KEY (custom_agent_id) REFERENCES public.custom_agents(id);


